Javascript.validate:
var val = Services.getValue(MaximumFine.dataBinding);
var err = null;
var maxVal = 999999.99;


if('0.00' != val)
{
	err = validateCurrencyValue(val, maxVal);
	if( null == err )
	{ 	
		var fVal = WPU.formatToTwoDP(val);
		Services.setValue(MaximumFine.dataBinding, fVal);
	}
}
return err;

Javascript.miscCode:
function DefaultCurrency806() {}
DefaultCurrency806.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency806.tabIndex = -1;
DefaultCurrency806.maxLength = 1;
DefaultCurrency806.isReadOnly = function(){return true;}
DefaultCurrency806.isTemporary = function(){return true;}
DefaultCurrency806.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency806.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
